}

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Delayed,
    Returned
}

namespace ShipmentTracker.Data;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public string Status { get; set; } = "Pending";
    public DateTime ShippedDate { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public DateTime? ActualDelivery { get; set; }
    public string CustomerEmail { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public interface IShipmentService
{
    Task<List<ShipmentDto>> GetAllShipmentsAsync();
    Task<ShipmentDto?> TrackShipmentAsync(string trackingNumber);
    Task<bool> UpdateStatusAsync(int id, ShipmentStatus newStatus);
}

using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentHttpService : IShipmentService
{
    private readonly HttpClient _http;

    public ShipmentHttpService(HttpClient http)
    {
        _http = http;
    }

    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        var result = await _http.GetFromJsonAsync<List<ShipmentDto>>("api/shipments");
        return result ?? new List<ShipmentDto>();
    }

    public async Task<ShipmentDto?> TrackShipmentAsync(string trackingNumber)
    {
        try
        {
            return await _http.GetFromJsonAsync<ShipmentDto>($"api/shipments/track/{trackingNumber}");
        }
        catch (HttpRequestException)
        {
            return null;
        }
    }

    public async Task<bool> UpdateStatusAsync(int id, ShipmentStatus newStatus)
    {
        var response = await _http.PutAsJsonAsync($"api/shipments/{id}/status", new { Status = newStatus.ToString() });
        return response.IsSuccessStatusCode;
    }
}

using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService : IShipmentService
{
    private readonly ApplicationDbContext _db;

    public ShipmentServerService(ApplicationDbContext db)
    {
        _db = db;
    }

    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await _db.Shipments.Select(s => MapToDto(s)).ToListAsync();
    }

    public async Task<ShipmentDto?> TrackShipmentAsync(string trackingNumber)
    {
        var shipment = await _db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return shipment is null ? null : MapToDto(shipment);
    }

    public async Task<bool> UpdateStatusAsync(int id, ShipmentStatus newStatus)
    {
        var shipment = await _db.Shipments.FindAsync(id);
        if (shipment is null) return false;

        shipment.Status = newStatus.ToString();
        if (newStatus == ShipmentStatus.Delivered)
            shipment.ActualDelivery = DateTime.UtcNow;

        await _db.SaveChangesAsync();
        return true;
    }

    private static ShipmentDto MapToDto(Data.Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = Enum.TryParse<ShipmentStatus>(s.Status, out var status) ? status : ShipmentStatus.Pending,
        ShippedDate = s.ShippedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        ActualDelivery = s.ActualDelivery,
        CustomerEmail = s.CustomerEmail,
        Description = s.Description
    };
}

using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments");

        group.MapGet("/", async (ApplicationDbContext db) =>
        {
            var shipments = await db.Shipments.ToListAsync();
            return Results.Ok(shipments.Select(MapToDto).ToList());
        }).RequireAuthorization(policy => policy.RequireRole("Dispatcher"));

        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(MapToDto(shipment));
        }).RequireAuthorization();

        group.MapPut("/{id}/status", async (int id, StatusUpdateRequest request, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();

            shipment.Status = request.Status;
            if (request.Status == ShipmentStatus.Delivered.ToString())
                shipment.ActualDelivery = DateTime.UtcNow;

            await db.SaveChangesAsync();
            return Results.Ok(MapToDto(shipment));
        }).RequireAuthorization(policy => policy.RequireRole("Dispatcher"));
    }

    private static ShipmentDto MapToDto(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = Enum.TryParse<ShipmentStatus>(s.Status, out var status) ? status : ShipmentStatus.Pending,
        ShippedDate = s.ShippedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        ActualDelivery = s.ActualDelivery,
        CustomerEmail = s.CustomerEmail,
        Description = s.Description
    };
}

public record StatusUpdateRequest(string Status);

