@page "/dispatcher"
@rendermode InteractiveAuto
@attribute [Authorize(Roles = "Dispatcher")]
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2 class="mb-4">📦 Dispatcher Dashboard</h2>

<div class="mb-3">
    <input type="text" class="form-control" placeholder="Search by tracking number or destination..."
           @bind="searchTerm" @bind:event="oninput" />
</div>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!FilteredShipments.Any())
{
    <p>No shipments found.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Shipped Date</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in FilteredShipments)
                {
                    <tr>
                        <td><strong>@shipment.TrackingNumber</strong></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td>
                            <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                    @bind="statusUpdates[shipment.Id]">
                                @foreach (var status in Enum.GetValues<ShipmentStatus>())
                                {
                                    <option value="@status">@status</option>
                                }
                            </select>
                        </td>
                        <td>@shipment.ShippedDate.ToString("MMM dd, yyyy")</td>
                        <td>@(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</td>
                        <td>
                            <button class="btn btn-sm btn-primary" @onclick="() => SaveStatus(shipment)"
                                    disabled="@(saving == shipment.Id)">
                                @(saving == shipment.Id ? "Saving..." : "Save")
                            </button>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@if (!string.IsNullOrEmpty(message))
{
    <div class="alert @(messageIsError ? "alert-danger" : "alert-success") mt-3" role="alert">
        @message
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private Dictionary<int, ShipmentStatus> statusUpdates = new();
    private string searchTerm = string.Empty;
    private int? saving;
    private string? message;
    private bool messageIsError;

    private IEnumerable<ShipmentDto> FilteredShipments =>
        shipments?.Where(s =>
            string.IsNullOrWhiteSpace(searchTerm) ||
            s.TrackingNumber.Contains(searchTerm, StringComparison.OrdinalIgnoreCase) ||
            s.Destination.Contains(searchTerm, StringComparison.OrdinalIgnoreCase)
        ) ?? Enumerable.Empty<ShipmentDto>();

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
        foreach (var s in shipments)
            statusUpdates[s.Id] = s.Status;
    }

    private async Task SaveStatus(ShipmentDto shipment)
    {
        saving = shipment.Id;
        message = null;

        var newStatus = statusUpdates[shipment.Id];
        var success = await ShipmentService.UpdateStatusAsync(shipment.Id, newStatus);

        if (success)
        {
            shipment.Status = newStatus;
            message = $"Status for {shipment.TrackingNumber} updated to {newStatus}.";
            messageIsError = false;
        }
        else
        {
            message = $"Failed to update status for {shipment.TrackingNumber}.";
            messageIsError = true;
        }

        saving = null;
    }
}

@page "/track"
@rendermode InteractiveAuto
@attribute [Authorize]
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h2 class="mb-4">🔍 Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number..."
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackShipment" disabled="@loading">
                @(loading ? "Tracking..." : "Track")
            </button>
        </div>
    </div>
</div>

@if (searched && shipment is null && !loading)
{
    <div class="alert alert-warning">
        <strong>Not found.</strong> No shipment found with tracking number "@trackingNumber".
    </div>
}

@if (shipment is not null)
{
    <div class="card mb-4">
        <div class="card-header">
            <h5 class="mb-0">Shipment: @shipment.TrackingNumber</h5>
        </div>
        <div class="card-body">
            <div class="row mb-3">
                <div class="col-md-6">
                    <p><strong>Route:</strong> @shipment.Origin → @shipment.Destination</p>
                    <p><strong>Description:</strong> @shipment.Description</p>
                    <p><strong>Status:</strong> <span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span></p>
                </div>
                <div class="col-md-6">
                    <p><strong>Shipped:</strong> @shipment.ShippedDate.ToString("MMM dd, yyyy")</p>
                    <p><strong>Estimated Delivery:</strong> @(shipment.EstimatedDelivery?.ToString("MMM dd, yyyy") ?? "—")</p>
                    @if (shipment.ActualDelivery.HasValue)
                    {
                        <p><strong>Delivered:</strong> @shipment.ActualDelivery.Value.ToString("MMM dd, yyyy")</p>
                    }
                </div>
            </div>

            <h6 class="mt-4 mb-3">Shipment Progress</h6>
            <div class="d-flex justify-content-between position-relative mb-3">
                @{
                    var steps = new[] {
                        ShipmentStatus.Pending,
                        ShipmentStatus.PickedUp,
                        ShipmentStatus.InTransit,
                        ShipmentStatus.OutForDelivery,
                        ShipmentStatus.Delivered
                    };
                    var currentIndex = Array.IndexOf(steps, shipment.Status);
                    var isException = shipment.Status == ShipmentStatus.Delayed || shipment.Status == ShipmentStatus.Returned;
                }
                @for (int i = 0; i < steps.Length; i++)
                {
                    var step = steps[i];
                    var isActive = !isException && i <= currentIndex;
                    var isCurrent = !isException && i == currentIndex;
                    <div class="text-center flex-fill">
                        <div class="rounded-circle mx-auto d-flex align-items-center justify-content-center"
                             style="width: 40px; height: 40px; background-color: @(isActive ? "#198754" : "#dee2e6"); color: @(isActive ? "white" : "#6c757d");">
                            @if (isCurrent)
                            {
                                <span>●</span>
                            }
                            else if (isActive)
                            {
                                <span>✓</span>
                            }
                            else
                            {
                                <span>@(i + 1)</span>
                            }
                        </div>
                        <small class="d-block mt-1 @(isActive ? "fw-bold" : "text-muted")">@step</small>
                    </div>
                }
            </div>

            @if (isException)
            {
                <div class="alert @(shipment.Status == ShipmentStatus.Delayed ? "alert-warning" : "alert-danger") mt-3">
                    <strong>@shipment.Status:</strong>
                    @if (shipment.Status == ShipmentStatus.Delayed)
                    {
                        <span>This shipment is currently delayed. We apologize for the inconvenience.</span>
                    }
                    else
                    {
                        <span>This shipment has been returned to the sender.</span>
                    }
                </div>
            }
        </div>
    </div>
}

@code {
    private string trackingNumber = string.Empty;
    private ShipmentDto? shipment;
    private bool loading;
    private bool searched;

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        loading = true;
        searched = true;
        shipment = null;

        shipment = await ShipmentService.TrackShipmentAsync(trackingNumber.Trim());

        loading = false;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info text-dark",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-warning text-dark",
        ShipmentStatus.Returned => "bg-danger",
        _ => "bg-secondary"
    };
}

